// src/components/SlideOver.jsx
import React, { useEffect, useRef } from 'react';

export default function SlideOver({ isOpen, onClose, title, width = 720, children }) {
  const panelRef = useRef(null);

  useEffect(() => {
    // lock body scroll when open
    document.body.style.overflow = isOpen ? 'hidden' : '';
    return () => {
      document.body.style.overflow = '';
    };
  }, [isOpen]);

  useEffect(() => {
    if (!isOpen) return;
    const onKey = (e) => {
      if (e.key === 'Escape') onClose?.();
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <div
      className="slide-over-overlay"
      role="dialog"
      aria-modal="true"
      aria-label={title || 'Slide over'}
      onMouseDown={(e) => {
        // close when clicking on overlay (but not when clicking inside panel)
        if (e.target === e.currentTarget) onClose?.();
      }}
      style={{
        position: 'fixed',
        inset: 0,
        zIndex: 1200,
        display: 'flex',
        justifyContent: 'flex-end',
        background: 'rgba(3,7,18,0.6)',
        backdropFilter: 'blur(6px)',
      }}
    >
      <div
        ref={panelRef}
        className="slide-over-panel"
        style={{
          width: width,
          maxWidth: '100%',
          height: '100%',
          background: 'var(--surface, #0b1220)',
          boxShadow: 'rgba(2,6,23,0.6)  -20px 0 60px',
          padding: 20,
          overflowY: 'auto',
          transform: 'translateX(0)',
          transition: 'transform 280ms cubic-bezier(.2,.9,.3,1)',
          borderLeft: '1px solid rgba(255,255,255,0.03)',
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
          <div style={{ display: 'flex', gap: 12, alignItems: 'center' }}>
            <h3 style={{ margin: 0, fontSize: 18, fontWeight: 800 }}>{title || 'Panel'}</h3>
          </div>
          <div style={{ display: 'flex', gap: 8 }}>
            <button
              aria-label="Close"
              onClick={onClose}
              style={{
                background: 'transparent',
                border: 'none',
                color: 'var(--text-muted)',
                cursor: 'pointer',
                fontSize: 16,
                padding: 8,
              }}
            >
              ✕
            </button>
          </div>
        </div>

        <div>{children}</div>
      </div>
    </div>
  );
}