// src/components/AvailableSlots.jsx
import React, { useMemo, useState, useRef, useEffect } from 'react';
import { useQuery } from '@tanstack/react-query';
import { useNavigate } from 'react-router-dom';
import api from '../services/api';

/**
 * Props:
 * - onSelect(slot) optional: called when user chooses a slot (slot object)
 * - initialFilter: optional object e.g. { status: 'AVAILABLE' }
 */
export default function AvailableSlots({ onSelect, initialFilter = { status: 'AVAILABLE' } }) {
  const { data: slots = [], isLoading } = useQuery({
    queryKey: ['slots'],
    queryFn: () => api.get('/slots').then((r) => r.data),
  });

  const [q, setQ] = useState('');
  const navigate = useNavigate();
  const searchRef = useRef(null);

  useEffect(() => {
    searchRef.current?.focus();
  }, []);

  // normalize minimal slot fields used for display
  const normalized = useMemo(() => {
    if (!Array.isArray(slots)) return [];
    return slots.map((s) => ({
      id: s.id ?? s.slot_id ?? null,
      slot_number: s.slot_number ?? s.code ?? s.name ?? String(s.id ?? ''),
      status: String(s.status || 'AVAILABLE').toUpperCase(),
      level: s.level ?? 'G',
      price_per_hour: s.price_per_hour ?? s.price ?? 5,
      ...s,
    }));
  }, [slots]);

  const filtered = useMemo(() => {
    return normalized.filter((s) => {
      if (initialFilter?.status && initialFilter.status !== 'ALL') {
        if (String(s.status).toUpperCase() !== String(initialFilter.status).toUpperCase()) return false;
      }
      if (!q) return true;
      const qq = q.trim().toLowerCase();
      return (
        String(s.slot_number).toLowerCase().includes(qq) ||
        String(s.level || '').toLowerCase().includes(qq) ||
        String(s.type || '').toLowerCase().includes(qq)
      );
    });
  }, [normalized, q, initialFilter]);

  const handleSelect = (slot) => {
    if (onSelect) {
      onSelect(slot);
    } else {
      // default behavior: navigate to booking page with state
      navigate('/booking', { state: { selectedSlot: slot } });
    }
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
      <div style={{ display: 'flex', gap: 8 }}>
        <input
          ref={searchRef}
          value={q}
          onChange={(e) => setQ(e.target.value)}
          placeholder="Search slot (e.g. A-1), level or type..."
          style={{
            flex: 1,
            padding: '10px 14px',
            borderRadius: 10,
            background: 'rgba(255,255,255,0.02)',
            border: '1px solid rgba(255,255,255,0.04)',
            color: 'var(--text-primary)',
          }}
        />
        <button
          type="button"
          onClick={() => {
            // quick find: go to first match
            if (filtered.length === 0) return;
            handleSelect(filtered[0]);
          }}
          className="btn-suprs"
          style={{ padding: '10px 16px' }}
        >
          Quick Book
        </button>
      </div>

      <div style={{ color: 'var(--text-muted)', fontSize: 13 }}>
        Showing {filtered.length} of {normalized.length} slots
      </div>

      <div className="available-slots-grid" style={{ display: 'grid', gap: 12, gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))' }}>
        {isLoading ? (
          <div style={{ padding: 24, textAlign: 'center', color: 'var(--text-muted)' }}>Loading…</div>
        ) : filtered.length === 0 ? (
          <div style={{ padding: 24, color: 'var(--text-muted)' }}>No matching available slots.</div>
        ) : (
          filtered.map((s) => (
            <div key={s.id ?? s.slot_number} className="slot-card" style={{
              background: 'rgba(255,255,255,0.02)',
              border: '1px solid rgba(255,255,255,0.04)',
              borderRadius: 12,
              padding: 12,
              display: 'flex',
              flexDirection: 'column',
              gap: 8,
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div style={{ fontWeight: 800, color: 'var(--text-primary)' }}>{s.slot_number}</div>
                <div style={{ fontSize: 11, padding: '4px 8px', borderRadius: 999, background: s.status === 'AVAILABLE' ? 'rgba(16,185,129,0.12)' : 'rgba(245,158,11,0.12)', color: s.status === 'AVAILABLE' ? '#10b981' : '#f59e0b' }}>
                  {s.status}
                </div>
              </div>

              <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>Level {s.level} · ${s.price_per_hour}/hr</div>

              <div style={{ display: 'flex', gap: 8, marginTop: 6 }}>
                <button className="btn-suprs" style={{ flex: 1 }} onClick={() => handleSelect(s)}>
                  Book
                </button>
                <button
                  className="btn-ghost"
                  onClick={() => {
                    // open booking page in a new tab with selected slot in state (optional)
                    navigate('/booking', { state: { selectedSlot: s } });
                  }}
                >
                  Details
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}